//   count rainy and shine separately as you loop days times
//   each day: roll RANDOM(1,100); if roll <= chance -> rainy else -> shine
//   every day is exactly one state, so rainy + shine should equal days
//   return "balanced" if rainy + shine === days, else "leak"

// call rainyDays(40, 1000) and print the returned value

reference.pseudocode:
PROCEDURE rainyDays(chance, days)
{
  rainy ← 0
  shine ← 0
  REPEAT days TIMES
  {
    IF(RANDOM(1, 100) ≤ chance)
    {
      rainy ← rainy + 1
    }
    ELSE
    {
      shine ← shine + 1
    }
  }
  IF(rainy + shine = days)
  {
    RETURN("balanced")
  }
  RETURN("leak")
}
DISPLAY(rainyDays(40, 1000))

reference.python:
import random
def rainyDays(chance, days):
    rainy = 0
    shine = 0
    for i in range(days):
        if random.randint(1, 100) <= chance:
            rainy = rainy + 1
        else:
            shine = shine + 1
    if rainy + shine == days:
        return "balanced"
    return "leak"
print(rainyDays(40, 1000))

reference.javascript:
function rainyDays(chance, days) {
  let rainy = 0;
  let shine = 0;
  for (let i = 0; i < days; i = i + 1) {
    if (Math.floor(Math.random() * 100) + 1 <= chance) {
      rainy = rainy + 1;
    } else {
      shine = shine + 1;
    }
  }
  if (rainy + shine === days) {
    return "balanced";
  }
  return "leak";
}
console.log(rainyDays(40, 1000));
